/* Optimize the tossubax sequence. Note: subtraction is not commutative! */
{
    CodeEntry*  X;


    /* Inline the sbc */
    D->IP = D->OpIndex+1;

    /* Must be true because of OP_RHS_LOAD, only A needed */
    CHECK ((D->Rhs.A.Flags & LI_DIRECT) != 0);

